const fs = require('fs');
const knowledgePath = $env.KYROS_KNOWLEDGE_PATH || '/opt/kyros/knowledge/public';
let accessible = false;
let fileCount = 0;
try {
  const files = fs.readdirSync(knowledgePath).filter(f => f.endsWith('.md'));
  fileCount = files.length;
  accessible = fileCount > 0;
} catch(err) {
  accessible = false;
}
return [{ json: { wiki_accessible: accessible, file_count: fileCount, checked_at: new Date().toISOString() } }];
